// Japanese Miner v6.2.8 cosmetic artwork bundle 21
(()=>{window.JM_RECOLOR_DATA=Object.assign(window.JM_RECOLOR_DATA||{},{"short/hair/silver":"","short/hair/teal":"","short/jacket/academy":"","short/jacket/explorer":"","short/jacket/haori":"","short/pants/black":"","short/pants/denim":"","short/pants/khaki":""});window.getJapaneseMinerRecolor=window.getJapaneseMinerRecolor||((hair,part,id)=>{const value=window.JM_RECOLOR_DATA[hair+'/'+part+'/'+id];return value?'url("data:image/webp;base64,'+value+'")':'none';});})();
